130: /**
131:  * Header-To-Metadata examines request/response headers and either copies or
132:  * moves the values into request metadata based on configuration information.
133:  */
134: class HeaderToMetadataFilter : public Http::StreamFilter,
135:                                public Logger::Loggable<Logger::Id::filter> {
136: public:
137:   HeaderToMetadataFilter(const ConfigSharedPtr config);
138:   ~HeaderToMetadataFilter() override;
139: 
140:   // Http::StreamFilterBase
141:   void onDestroy() override {}
142: 
143:   // StreamDecoderFilter
144:   Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
145:   Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
146:     return Http::FilterDataStatus::Continue;
147:   }
148:   Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
149:     return Http::FilterTrailersStatus::Continue;
150:   }
151:   void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;
152: 
153:   // StreamEncoderFilter
154:   Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
155:     return Http::Filter1xxHeadersStatus::Continue;
156:   }
157:   Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
158:   Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
159:     return Http::FilterDataStatus::Continue;
160:   }
161:   Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
162:     return Http::FilterTrailersStatus::Continue;
163:   }
164:   Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
165:     return Http::FilterMetadataStatus::Continue;
166:   }
167:   void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;
168: 
169: private:
170:   friend class HeaderToMetadataTest;
171: 
172:   using StructMap = std::map<std::string, ProtobufWkt::Struct>;
173: 
174:   const ConfigSharedPtr config_;
175:   mutable const Config* effective_config_{nullptr};
176:   Http::StreamDecoderFilterCallbacks* decoder_callbacks_{};
177:   Http::StreamEncoderFilterCallbacks* encoder_callbacks_{};
178: 
179:   /**
180:    *  writeHeaderToMetadata encapsulates (1) searching for the header and (2) writing it to the
181:    *  request metadata.
182:    *  @param headers the map of key-value headers to look through. These could be response or
183:    *                 request headers depending on whether this is called from the encode state or
184:    *                 decode state.
185:    *  @param rules the header-to-metadata mapping set in configuration.
186:    *  @param callbacks the callback used to fetch the StreamInfo (which is then used to get
187:    *                   metadata). Callable with both encoder_callbacks_ and decoder_callbacks_.
188:    */
189:   void writeHeaderToMetadata(Http::HeaderMap& headers, const HeaderToMetadataRules& rules,
190:                              Http::StreamFilterCallbacks& callbacks);
191:   bool addMetadata(StructMap&, const std::string&, const std::string&, std::string, ValueType,
192:                    ValueEncode) const;
193:   void applyKeyValue(std::string&&, const Rule&, const KeyValuePair&, StructMap&);
194:   const std::string& decideNamespace(const std::string& nspace) const;
195:   const Config* getConfig() const;
196: };
