#pragma once

#include <memory>
#include <string>
#include <unordered_map>

#include "envoy/http/filter.h"
#include "envoy/server/filter_config.h"

#include "source/common/common/logger.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

/**
 * Configuration for header injection.
 */
struct HeaderInjectionConfig {
  std::unordered_map<std::string, std::string> request_headers;
  std::unordered_map<std::string, std::string> response_headers;
};

using ConfigSharedPtr = std::shared_ptr<HeaderInjectionConfig>;

/**
 * Custom Header Injection filter that injects configurable headers into
 * requests and/or responses.
 */
class CustomHeaderInjectionFilter : public Http::StreamFilter,
                                    public Logger::Loggable<Logger::Id::filter> {
public:
  explicit CustomHeaderInjectionFilter(const ConfigSharedPtr config);
  ~CustomHeaderInjectionFilter() override;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers, bool) override;
  Http::FilterDataStatus decodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;

  // StreamEncoderFilter
  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap&) override {
    return Http::Filter1xxHeadersStatus::Continue;
  }
  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers, bool) override;
  Http::FilterDataStatus encodeData(Buffer::Instance&, bool) override {
    return Http::FilterDataStatus::Continue;
  }
  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap&) override {
    return Http::FilterTrailersStatus::Continue;
  }
  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap&) override {
    return Http::FilterMetadataStatus::Continue;
  }
  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;

private:
  const ConfigSharedPtr config_;
};

} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

