Http::FilterFactoryCb CustomHeaderInjectionConfigFactory::createFilterFactoryFromProtoTyped(
    const CustomHeaderInjectionConfig& proto_config, const std::string&,
    Server::Configuration::FactoryContext&) {
  // Create a HeaderInjectionConfig from the protobuf config
  auto filter_config = std::make_shared<HeaderInjectionConfig>();
  filter_config->request_headers = proto_config.requestHeaders();
  filter_config->response_headers = proto_config.responseHeaders();

  return [filter_config](Http::FilterChainFactoryCallbacks& callbacks) -> void {
    callbacks.addStreamFilter(Http::StreamFilterSharedPtr{new CustomHeaderInjectionFilter(filter_config)});
