  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
};

// Test that request headers are injected
TEST_F(CustomHeaderInjectionFilterTest, InjectRequestHeaders) {
  Http::TestRequestHeaderMapImpl request_headers{};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, true));

  EXPECT_EQ("request-value", request_headers.get_("x-injected-request"));
}

// Test that response headers are injected
TEST_F(CustomHeaderInjectionFilterTest, InjectResponseHeaders) {
  Http::TestResponseHeaderMapImpl response_headers{};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, true));

  EXPECT_EQ("response-value", response_headers.get_("x-injected-response"));
}

