TEST_F(CustomHeaderInjectionFilterTest, InjectMultipleHeaders) {
  auto config = std::make_shared<HeaderInjectionConfig>();
  config->request_headers["x-header-1"] = "value1";
  config->request_headers["x-header-2"] = "value2";
  config->request_headers["x-header-3"] = "value3";

