  filter->setDecoderFilterCallbacks(decoder_callbacks_);

  Http::TestRequestHeaderMapImpl request_headers{};

  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter->decodeHeaders(request_headers, true));

  EXPECT_EQ("value1", request_headers.get_("x-header-1"));
  EXPECT_EQ("value2", request_headers.get_("x-header-2"));
  EXPECT_EQ("value3", request_headers.get_("x-header-3"));
}

// Test with empty config
TEST_F(CustomHeaderInjectionFilterTest, EmptyConfig) {
  auto config = std::make_shared<HeaderInjectionConfig>();
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(config);
  filter->setDecoderFilterCallbacks(decoder_callbacks_);
  filter->setEncoderFilterCallbacks(encoder_callbacks_);

  Http::TestRequestHeaderMapImpl request_headers{};
  Http::TestResponseHeaderMapImpl response_headers{};

  // Should continue without errors
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter->decodeHeaders(request_headers, true));
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter->encodeHeaders(response_headers, true));
}

// Test filter lifecycle methods
TEST_F(CustomHeaderInjectionFilterTest, FilterLifecycleMethods) {
  auto config = std::make_shared<HeaderInjectionConfig>();
  auto filter = std::make_shared<CustomHeaderInjectionFilter>(config);

  // Test that these methods don't crash
  filter->onDestroy();

  Http::TestRequestHeaderMapImpl request_headers{};
  Buffer::OwnedImpl data;
  Http::RequestTrailerMap trailers;

  EXPECT_EQ(Http::FilterDataStatus::Continue, filter->decodeData(data, true));
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter->decodeTrailers(trailers));

  Http::TestResponseHeaderMapImpl response_headers{};
  EXPECT_EQ(Http::Filter1xxHeadersStatus::Continue,
            filter->encode1xxHeaders(response_headers));

  Http::ResponseTrailerMap response_trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter->encodeTrailers(response_trailers));

  Http::MetadataMap metadata;
  EXPECT_EQ(Http::FilterMetadataStatus::Continue, filter->encodeMetadata(metadata));
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

